#ifndef DSA_TOPK_INDEXER_FP8_H64_D128_TOPK2048_PS64_KERNEL_H_
#define DSA_TOPK_INDEXER_FP8_H64_D128_TOPK2048_PS64_KERNEL_H_

#include <cstdint>
#include <cuda_runtime.h>

constexpr int kNumIndexHeads = 64;
constexpr int kIndexHeadDim  = 128;
constexpr int kPageSize      = 64;
constexpr int kTopK          = 2048;

// deep_gemm packed per page: fp8 bytes (page_size*128) then scales (page_size*4)
constexpr int kPageBytes = kPageSize * kIndexHeadDim + kPageSize * 4;
constexpr int kScaleBase = kPageSize * kIndexHeadDim;

struct LaunchParams {
  int batch_size;
  int max_num_pages;
  int num_pages;
};

cudaError_t launch_dsa_topk_indexer(
    const void* q_index_fp8,            // [B,64,128] fp8 bytes (1 byte each)
    const uint8_t* k_index_cache_u8,    // packed per page bytes (uint8 view of int8 storage)
    const float* weights,              // [B,64] fp32
    const int32_t* seq_lens,            // [B] int32
    const int32_t* block_table,         // [B,max_num_pages] int32
    int32_t* topk_indices,              // [B,2048] int32
    LaunchParams p,
    cudaStream_t stream);

#endif  // DSA_TOPK_INDEXER_FP8_H64_D128_TOPK2048_PS64_KERNEL_H_

#include "kernel.h"

#include <cuda.h>
#include <cuda_runtime.h>
#include <stdint.h>

#if defined(__CUDA_ARCH__)
  #define FI_LDG(ptr) __ldg(ptr)
#else
  #define FI_LDG(ptr) (*(ptr))
#endif

static_assert(kTopK == 2048, "specialized for topk=2048");
static_assert(kPageSize == 64, "specialized for page_size=64");
static_assert(kIndexHeadDim == 128, "specialized for head_dim=128");
static_assert(kNumIndexHeads == 64, "specialized for 64 heads");

__device__ __forceinline__ float relu_f(float x) { return x > 0.f ? x : 0.f; }

// FP8 E4M3FN decode (finite-only) into float.
// This matches common E4M3FN behavior closely enough for scoring.
__device__ __forceinline__ float fp8e4m3fn_to_f32(uint8_t x) {
  const uint32_t sign = (x >> 7) & 1u;
  const uint32_t exp  = (x >> 3) & 0xFu;
  const uint32_t mant = (x & 0x7u);

  float f;
  if (exp == 0u) {
    if (mant == 0u) {
      f = 0.0f;
    } else {
      // subnormal
      f = ldexpf((float)mant, -9);
    }
  } else if (exp == 0xFu) {
    // finite-only clamp
    f = 240.0f;
  } else {
    const float m = 1.0f + (float)mant * 0.125f;
    f = ldexpf(m, (int)exp - 7);
  }
  return sign ? -f : f;
}

__device__ __forceinline__ const uint8_t* page_base_ptr(const uint8_t* kcache, int32_t global_page) {
  return kcache + (size_t)global_page * (size_t)kPageBytes;
}

__device__ __forceinline__ float load_scale(const uint8_t* __restrict__ page_base, int tok) {
  const uint8_t* p = page_base + kScaleBase + tok * 4;
  uint32_t u = (uint32_t)p[0] |
               ((uint32_t)p[1] << 8) |
               ((uint32_t)p[2] << 16) |
               ((uint32_t)p[3] << 24);
  return __uint_as_float(u);
}

struct Pair {
  float score;
  int32_t idx;  // token index in [0, seq_len)
};

__device__ __forceinline__ void heapify_down(Pair* heap, int heap_size, int i) {
  while (true) {
    int l = 2 * i + 1;
    int r = l + 1;
    int s = i;
    if (l < heap_size && heap[l].score < heap[s].score) s = l;
    if (r < heap_size && heap[r].score < heap[s].score) s = r;
    if (s == i) break;
    Pair tmp = heap[i];
    heap[i] = heap[s];
    heap[s] = tmp;
    i = s;
  }
}
__device__ __forceinline__ void heap_build(Pair* heap, int heap_size) {
  for (int i = heap_size / 2 - 1; i >= 0; --i) heapify_down(heap, heap_size, i);
}
__device__ __forceinline__ void heap_insert_topk(Pair* heap, int K, Pair v) {
  if (v.score <= heap[0].score) return;
  heap[0] = v;
  heapify_down(heap, K, 0);
}
__device__ __forceinline__ void heap_sort_desc(Pair* heap, int heap_size) {
  for (int end = heap_size - 1; end > 0; --end) {
    Pair tmp = heap[0];
    heap[0] = heap[end];
    heap[end] = tmp;
    heapify_down(heap, end, 0);
  }
}

template<int LOCAL_K>
__device__ __forceinline__ void local_insert(Pair* buf, int& sz, Pair v) {
  if (sz < LOCAL_K) {
    buf[sz++] = v;
    return;
  }
  int min_i = 0;
  float min_s = buf[0].score;
  #pragma unroll
  for (int i = 1; i < LOCAL_K; ++i) {
    if (buf[i].score < min_s) { min_s = buf[i].score; min_i = i; }
  }
  if (v.score > min_s) buf[min_i] = v;
}

__global__ void topk_kernel_one_block_per_batch(
    const uint8_t* __restrict__ q_fp8,        // [B,64,128] fp8 bytes
    const uint8_t* __restrict__ kcache,       // packed per page bytes
    const float* __restrict__ weights,        // [B,64]
    const int32_t* __restrict__ seq_lens,     // [B]
    const int32_t* __restrict__ block_table,  // [B,max_num_pages]
    int32_t* __restrict__ out_topk_indices,   // [B,2048]
    LaunchParams p)
{
  const int b = (int)blockIdx.x;
  const int tid = (int)threadIdx.x;

  const int32_t seq_len = FI_LDG(seq_lens + b);
  const uint8_t* q_b = q_fp8 + (size_t)b * kNumIndexHeads * kIndexHeadDim;
  const float* w_b = weights + (size_t)b * kNumIndexHeads;
  const int32_t* bt_b = block_table + (size_t)b * p.max_num_pages;

  extern __shared__ uint8_t smem_raw[];
  Pair* heap = reinterpret_cast<Pair*>(smem_raw);
  __shared__ int mutex;

  if (seq_len <= 0) {
    for (int i = tid; i < kTopK; i += blockDim.x) {
      out_topk_indices[(size_t)b * kTopK + i] = -1;
    }
    return;
  }

  if (tid == 0) mutex = 0;

  // init heap
  for (int i = tid; i < kTopK; i += blockDim.x) {
    heap[i].score = -1e30f;
    heap[i].idx = -1;
  }
  __syncthreads();
  if (tid == 0) heap_build(heap, kTopK);
  __syncthreads();

  constexpr int LOCAL_K = 8;
  Pair local_buf[LOCAL_K];
  int local_sz = 0;

  for (int t = tid; t < seq_len; t += blockDim.x) {
    const int page_in_seq = t >> 6;
    const int off_in_page = t & 63;

    if ((uint32_t)page_in_seq >= (uint32_t)p.max_num_pages) continue;
    const int32_t global_page = FI_LDG(bt_b + page_in_seq);
    if ((uint32_t)global_page >= (uint32_t)p.num_pages) continue;

    const uint8_t* pb = page_base_ptr(kcache, global_page);

    // Correct deep_gemm packing:
    // fp8 region: pb + [0 .. page_size*128)
    // per-token fp8: pb + off*128 (NOT off*132)
    const uint8_t* k_tok = pb + off_in_page * kIndexHeadDim;
    const float scale = load_scale(pb, off_in_page);

    float final_score = 0.0f;

    #pragma unroll
    for (int h = 0; h < kNumIndexHeads; ++h) {
      const uint8_t* qh = q_b + h * kIndexHeadDim;
      float acc = 0.0f;

      #pragma unroll 8
      for (int d = 0; d < kIndexHeadDim; ++d) {
        const float qv = fp8e4m3fn_to_f32(FI_LDG(qh + d));
        const float kv = fp8e4m3fn_to_f32(FI_LDG(k_tok + d)) * scale;
        acc = fmaf(qv, kv, acc);
      }
      acc = relu_f(acc);
      final_score = fmaf(acc, FI_LDG(w_b + h), final_score);
    }

    local_insert<LOCAL_K>(local_buf, local_sz, Pair{final_score, (int32_t)t});
  }

  // Merge local into shared heap
  if (local_sz > 0) {
    while (atomicCAS(&mutex, 0, 1) != 0) {}
    #pragma unroll
    for (int i = 0; i < LOCAL_K; ++i) {
      if (i < local_sz) heap_insert_topk(heap, kTopK, local_buf[i]);
    }
    __threadfence_block();
    atomicExch(&mutex, 0);
  }

  __syncthreads();
  if (tid == 0) heap_sort_desc(heap, kTopK);
  __syncthreads();

  const int actual_topk = (seq_len < kTopK) ? seq_len : kTopK;

  for (int i = tid; i < kTopK; i += blockDim.x) {
    int32_t out = -1;
    if (i < actual_topk) {
      const int32_t t = heap[i].idx;
      if ((uint32_t)t < (uint32_t)seq_len) {
        const int page_in_seq = t >> 6;
        const int off = t & 63;
        const int32_t global_page = FI_LDG(bt_b + page_in_seq);
        if ((uint32_t)global_page < (uint32_t)p.num_pages) {
          out = global_page * kPageSize + off;
        }
      }
    }
    out_topk_indices[(size_t)b * kTopK + i] = out;
  }
}

cudaError_t launch_dsa_topk_indexer(
    const void* q_index_fp8,
    const uint8_t* k_index_cache_u8,
    const float* weights,
    const int32_t* seq_lens,
    const int32_t* block_table,
    int32_t* topk_indices,
    LaunchParams p,
    cudaStream_t stream)
{
  dim3 grid((unsigned)p.batch_size, 1, 1);
  const int threads = 256;
  const size_t shmem = (size_t)kTopK * sizeof(Pair); // 2048 * 8 = 16384 bytes

  topk_kernel_one_block_per_batch<<<grid, threads, shmem, stream>>>(
      (const uint8_t*)q_index_fp8,
      k_index_cache_u8,
      weights,
      seq_lens,
      block_table,
      topk_indices,
      p);

  return cudaGetLastError();
}

#include <torch/extension.h>
#include <ATen/cuda/CUDAContext.h>
#include <cuda_runtime.h>

#include <sstream>
#include <stdexcept>

#include "kernel.h"

static inline void cuda_check(cudaError_t err, const char* what) {
  if (err != cudaSuccess) {
    std::ostringstream oss;
    oss << what << ": " << cudaGetErrorString(err);
    throw std::runtime_error(oss.str());
  }
}

static inline void check_cuda_contig(const torch::Tensor& t, const char* name) {
  TORCH_CHECK(t.defined(), name, " must be defined");
  TORCH_CHECK(t.device().is_cuda(), name, " must be a CUDA tensor");
  TORCH_CHECK(t.is_contiguous(), name, " must be contiguous");
}

torch::Tensor run(torch::Tensor q_index_fp8,
                  torch::Tensor k_index_cache_fp8,
                  torch::Tensor weights,
                  torch::Tensor seq_lens,
                  torch::Tensor block_table) {
  check_cuda_contig(q_index_fp8, "q_index_fp8");
  check_cuda_contig(k_index_cache_fp8, "k_index_cache_fp8");
  check_cuda_contig(weights, "weights");
  check_cuda_contig(seq_lens, "seq_lens");
  check_cuda_contig(block_table, "block_table");

  TORCH_CHECK(q_index_fp8.dim() == 3, "q_index_fp8 must be [B,64,128]");
  TORCH_CHECK(q_index_fp8.size(1) == kNumIndexHeads, "q_index_fp8 heads must be 64");
  TORCH_CHECK(q_index_fp8.size(2) == kIndexHeadDim, "q_index_fp8 dim must be 128");
  TORCH_CHECK(q_index_fp8.element_size() == 1,
              "q_index_fp8 must be a 1-byte tensor (float8 or uint8/int8 storage)");

  TORCH_CHECK(k_index_cache_fp8.dim() == 4, "k_index_cache_fp8 must be [num_pages,64,1,132]");
  TORCH_CHECK(k_index_cache_fp8.size(1) == kPageSize, "page_size must be 64");
  TORCH_CHECK(k_index_cache_fp8.size(2) == 1, "kv_cache_num_heads must be 1");
  TORCH_CHECK(k_index_cache_fp8.size(3) == 132, "head_dim_with_scale must be 132");
  TORCH_CHECK(k_index_cache_fp8.scalar_type() == at::kChar,
              "k_index_cache_fp8 must be int8 (byte storage), interpreted as uint8");

  TORCH_CHECK(weights.scalar_type() == at::kFloat, "weights must be float32");
  TORCH_CHECK(weights.dim() == 2 && weights.size(1) == kNumIndexHeads, "weights must be [B,64]");

  TORCH_CHECK(seq_lens.scalar_type() == at::kInt, "seq_lens must be int32");
  TORCH_CHECK(seq_lens.dim() == 1, "seq_lens must be [B]");

  TORCH_CHECK(block_table.scalar_type() == at::kInt, "block_table must be int32");
  TORCH_CHECK(block_table.dim() == 2, "block_table must be [B,max_num_pages]");

  const int64_t B = q_index_fp8.size(0);
  TORCH_CHECK(weights.size(0) == B, "weights first dim must equal batch_size");
  TORCH_CHECK(seq_lens.size(0) == B, "seq_lens size must equal batch_size");
  TORCH_CHECK(block_table.size(0) == B, "block_table first dim must equal batch_size");

  const int64_t num_pages = k_index_cache_fp8.size(0);
  const int64_t max_num_pages = block_table.size(1);
  TORCH_CHECK((int64_t)kTopK <= max_num_pages * kPageSize,
              "constraint violated: topk <= max_num_pages*page_size");

  // IMPORTANT: use the current PyTorch CUDA stream, not default stream.
  cudaStream_t stream = at::cuda::getDefaultCUDAStream(q_index_fp8.device().index());

  auto topk_indices = torch::full(
      {B, (int64_t)kTopK}, -1,
      torch::TensorOptions().device(q_index_fp8.device()).dtype(at::kInt));

  LaunchParams p;
  p.batch_size = (int)B;
  p.max_num_pages = (int)max_num_pages;
  p.num_pages = (int)num_pages;

  cuda_check(
      launch_dsa_topk_indexer(
          (const void*)q_index_fp8.data_ptr(),
          (const uint8_t*)k_index_cache_fp8.data_ptr<int8_t>(),
          (const float*)weights.data_ptr<float>(),
          (const int32_t*)seq_lens.data_ptr<int32_t>(),
          (const int32_t*)block_table.data_ptr<int32_t>(),
          (int32_t*)topk_indices.data_ptr<int32_t>(),
          p,
          stream),
      "launch_dsa_topk_indexer failed");

  cuda_check(cudaGetLastError(), "CUDA error after kernel launch");
  cuda_check(cudaStreamSynchronize(stream), "cudaStreamSynchronize failed");

  return topk_indices;
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
  m.def("run", &run, "Kernel execution function",
        pybind11::arg("q_index_fp8"),
        pybind11::arg("k_index_cache_fp8"),
        pybind11::arg("weights"),
        pybind11::arg("seq_lens"),
        pybind11::arg("block_table"));
}
